var rate = parseFloat(vatRate) / 100;
    var net, vat, gross;
    if (direction === 'add') {
      net = amount;
      vat = amount * rate;
      gross = amount + vat;
    } else {
      gross = amount;
      net = amount / (1 + rate);
      vat = gross - net;
    }
    var total = gross * quantity;
    document.getElementById('netAmount').textContent = '\u00A3' + net.toFixed(2);
    document.getElementById('vatAmount').textContent = '\u00A3' + vat.toFixed(2);
    document.getElementById('grossAmount').textContent = '\u00A3' + gross.toFixed(2);
    document.getElementById('totalWithQty').textContent = '\u00A3' + total.toFixed(2);

var price = propertyPrice;
    var sdlt = 0;
    var surcharge = buyerType === 'additional' ? 0.03 : 0;
    if (buyerType === 'ftb' && price <= 625000) {
      if (price <= 425000) { sdlt = 0; }
      else { sdlt = (price - 425000) * 0.05; }
    } else {
      if (price > 250000) { sdlt += Math.min(price, 925000) > 250000 ? (Math.min(price, 925000) - 250000) * 0.05 : 0; }
      if (price > 925000) { sdlt += (Math.min(price, 1500000) - 925000) * 0.10; }
      if (price > 1500000) { sdlt += (price - 1500000) * 0.12; }
    }
    sdlt += price * surcharge;
    var effRate = price > 0 ? (sdlt / price * 100) : 0;
    var totalCost = price + sdlt;
    var breakdown = '';
    if (buyerType === 'ftb' && price <= 625000) {
      breakdown = '0% on first \u00A3425k, 5% on \u00A3425k-\u00A3625k';
    } else {
      breakdown = '0% up to \u00A3250k, 5% \u00A3250k-\u00A3925k, 10% \u00A3925k-\u00A31.5m, 12% above \u00A31.5m';
    }
    if (surcharge > 0) breakdown += ' + 3% surcharge';
    document.getElementById('totalSDLT').textContent = '\u00A3' + sdlt.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('effectiveRate').textContent = effRate.toFixed(2) + '%';
    document.getElementById('totalCost').textContent = '\u00A3' + totalCost.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('bandBreakdown').textContent = breakdown;

var bandD = {average: 2171, london: 1898, southeast: 2152, northwest: 2191, northeast: 2190, midlands: 2175, southwest: 2290, yorkshire: 2108};
    var ratios = {A: 6/9, B: 7/9, C: 8/9, D: 1, E: 11/9, F: 13/9, G: 15/9, H: 2};
    var baseBandD = bandD[region] || 2171;
    var ratio = ratios[band] || 1;
    var annual = baseBandD * ratio;
    if (singleOccupant === 'yes') annual *= 0.75;
    var monthly = annual / parseFloat(paymentMonths);
    var weekly = annual / 52;
    document.getElementById('annualBill').textContent = '\u00A3' + annual.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('monthlyPayment').textContent = '\u00A3' + monthly.toFixed(2);
    document.getElementById('weeklyEquiv').textContent = '\u00A3' + weekly.toFixed(2);
    document.getElementById('bandRatio').textContent = ratio.toFixed(4) + ' (Band ' + band + ' vs Band D)';

var annual = annualIncome;
    if (payPeriod === 'monthly') annual = annualIncome * 12;
    if (payPeriod === 'weekly') annual = annualIncome * 52;
    var ni = 0;
    if (ageOver === 'no') {
      if (employmentType === 'employed') {
        var threshold = 12570;
        var upperLimit = 50270;
        if (annual > threshold) {
          ni += Math.min(annual, upperLimit) > threshold ? (Math.min(annual, upperLimit) - threshold) * 0.08 : 0;
        }
        if (annual > upperLimit) {
          ni += (annual - upperLimit) * 0.02;
        }
      } else {
        var class2 = 3.45 * 52;
        var lowerProfits = 12570;
        var upperProfits = 50270;
        var class4 = 0;
        if (annual > lowerProfits) {
          class4 += (Math.min(annual, upperProfits) - lowerProfits) * 0.06;
        }
        if (annual > upperProfits) {
          class4 += (annual - upperProfits) * 0.02;
        }
        ni = (annual >= 6725 ? class2 : 0) + class4;
      }
    }
    var monthlyNIval = ni / 12;
    var weeklyNIval = ni / 52;
    var effRate = annual > 0 ? (ni / annual * 100) : 0;
    var takeHome = annual - ni;
    document.getElementById('annualNI').textContent = '\u00A3' + ni.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('monthlyNI').textContent = '\u00A3' + monthlyNIval.toFixed(2);
    document.getElementById('weeklyNI').textContent = '\u00A3' + weeklyNIval.toFixed(2);
    document.getElementById('effectiveNIRate').textContent = effRate.toFixed(2) + '%';
    document.getElementById('takeHomePay').textContent = '\u00A3' + takeHome.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');

var income = grossIncome - pensionContrib;
    var pa = 12570;
    if (taxCode === 'blind') pa += 2870;
    if (income > 100000) {
      pa = Math.max(0, pa - (income - 100000) / 2);
    }
    var taxableIncome = Math.max(0, income - pa);
    var tax = 0;
    if (taxCode === 'scottish') {
      var bands = [{limit: 2162, rate: 0.19}, {limit: 13118 - 2162, rate: 0.20}, {limit: 31092 - 13118, rate: 0.21}, {limit: 62430 - 31092, rate: 0.42}, {limit: 125140 - 62430, rate: 0.45}, {limit: Infinity, rate: 0.48}];
      var remaining = taxableIncome;
      for (var i = 0; i < bands.length && remaining > 0; i++) {
        var chunk = Math.min(remaining, bands[i].limit);
        tax += chunk * bands[i].rate;
        remaining -= chunk;
      }
    } else {
      var basicLimit = 37700;
      if (giftAid > 0) basicLimit += giftAid * 0.25;
      if (taxableIncome <= basicLimit) {
        tax = taxableIncome * 0.20;
      } else if (taxableIncome <= 125140) {
        tax = basicLimit * 0.20 + (taxableIncome - basicLimit) * 0.40;
      } else {
        tax = basicLimit * 0.20 + (125140 - basicLimit) * 0.40 + (taxableIncome - 125140) * 0.45;
      }
    }
    var effRate = grossIncome > 0 ? (tax / grossIncome * 100) : 0;
    var monthlyTaxVal = tax / 12;
    var takeHomeAnn = grossIncome - tax;
    var takeHomeMon = takeHomeAnn / 12;
    document.getElementById('personalAllowance').textContent = '\u00A3' + pa.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('totalIncomeTax').textContent = '\u00A3' + tax.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('effectiveTaxRate').textContent = effRate.toFixed(2) + '%';
    document.getElementById('monthlyTax').textContent = '\u00A3' + monthlyTaxVal.toFixed(2);
    document.getElementById('takeHomeAnnual').textContent = '\u00A3' + takeHomeAnn.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('takeHomeMonthly').textContent = '\u00A3' + takeHomeMon.toFixed(2);

var qualifyingEarnings = Math.max(0, Math.min(salary, 50270) - 6240);
    var empContrib = qualifyingEarnings * (employeeRate / 100);
    var erContrib = qualifyingEarnings * (employerRate / 100);
    var totalAnnual = empContrib + erContrib;
    var taxRelief20 = empContrib * 0.25;
    var totalWithRelief = totalAnnual + taxRelief20;
    var monthlyEmp = empContrib / 12;
    var monthlyEr = erContrib / 12;
    var monthlyTotal = totalWithRelief / 12;
    var monthlyGrowth = growthRate / 100 / 12;
    var months = yearsToRetirement * 12;
    var futureVal = currentPot * Math.pow(1 + monthlyGrowth, months);
    for (var m = 0; m < months; m++) {
      futureVal += monthlyTotal * Math.pow(1 + monthlyGrowth, months - m - 1);
    }
    var annualIncome = futureVal * 0.04;
    document.getElementById('monthlyYou').textContent = '\u00A3' + monthlyEmp.toFixed(2);
    document.getElementById('monthlyEmployer').textContent = '\u00A3' + monthlyEr.toFixed(2);
    document.getElementById('monthlyTotal').textContent = '\u00A3' + monthlyTotal.toFixed(2);
    document.getElementById('taxRelief').textContent = '\u00A3' + taxRelief20.toFixed(2);
    document.getElementById('projectedPot').textContent = '\u00A3' + futureVal.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('annualDrawdown').textContent = '\u00A3' + annualIncome.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');

var thresholds = {plan1: 22015, plan2: 27295, plan4: 27660, plan5: 25000, postgrad: 21000};
    var rates = {plan1: 0.09, plan2: 0.09, plan4: 0.09, plan5: 0.09, postgrad: 0.06};
    var writeOffYears = {plan1: 25, plan2: 30, plan4: 30, plan5: 40, postgrad: 30};
    var threshold = thresholds[loanPlan];
    var repayRate = rates[loanPlan];
    var excess = Math.max(0, salary - threshold);
    var annualRepay = excess * repayRate;
    var monthlyRepay = annualRepay / 12;
    var balance = loanBalance;
    var totalPaid = 0;
    var years = 0;
    var maxYears = writeOffYears[loanPlan];
    var currentSal = salary;
    while (balance > 0 && years < maxYears) {
      var yearExcess = Math.max(0, currentSal - threshold);
      var yearRepay = Math.min(yearExcess * repayRate, balance + balance * (interestRate / 100));
      balance = balance * (1 + interestRate / 100) - yearRepay;
      totalPaid += yearRepay;
      years++;
      currentSal *= (1 + salaryGrowth / 100);
      if (balance <= 0) break;
    }
    if (balance > 0) { totalPaid = totalPaid; years = maxYears; }
    document.getElementById('monthlyRepayment').textContent = '\u00A3' + monthlyRepay.toFixed(2);
    document.getElementById('annualRepayment').textContent = '\u00A3' + annualRepay.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('repaymentThreshold').textContent = '\u00A3' + threshold.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',') + '/year';
    document.getElementById('yearsToRepay').textContent = balance > 0 ? years + ' (written off)' : years + ' years';
    document.getElementById('totalRepaid').textContent = '\u00A3' + totalPaid.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');

var loan = propertyPrice - deposit;
    var ltv = (loan / propertyPrice * 100);
    var monthlyRate = interestRate / 100 / 12;
    var numPayments = term * 12;
    var monthlyPmt = loan * monthlyRate * Math.pow(1 + monthlyRate, numPayments) / (Math.pow(1 + monthlyRate, numPayments) - 1);
    var totalRepaidVal = monthlyPmt * numPayments;
    var totalInterestVal = totalRepaidVal - loan;
    var price = propertyPrice;
    var sdlt = 0;
    var surcharge = buyerType === 'additional' ? 0.03 : 0;
    if (buyerType === 'ftb' && price <= 625000) {
      if (price > 425000) sdlt = (price - 425000) * 0.05;
    } else {
      if (price > 250000) sdlt += (Math.min(price, 925000) - 250000) * 0.05;
      if (price > 925000) sdlt += (Math.min(price, 1500000) - 925000) * 0.10;
      if (price > 1500000) sdlt += (price - 1500000) * 0.12;
    }
    sdlt += price * surcharge;
    var totalUpfrontVal = deposit + sdlt;
    document.getElementById('loanAmount').textContent = '\u00A3' + loan.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('monthlyPayment').textContent = '\u00A3' + monthlyPmt.toFixed(2);
    document.getElementById('stampDuty').textContent = '\u00A3' + sdlt.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('totalUpfront').textContent = '\u00A3' + totalUpfrontVal.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('totalRepaid').textContent = '\u00A3' + totalRepaidVal.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    document.getElementById('totalInterest').textContent = '\u00A3' + totalInterestVal.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',');

var elecP, gasP, elecStanding, gasStanding;
    if (tariffType === 'cap') {
      elecP = 24.50; gasP = 6.76;
      elecStanding = 61.64; gasStanding = 31.65;
    } else {
      elecP = elecRate; gasP = gasRate;
