      if (estateValue > 2000000) {
        var taperReduction = (estateValue - 2000000) / 2;
        rnrb = Math.max(0, rnrb - taperReduction);
      }
    }
    if (maritalStatus === 'married') {
      nrb *= 2;
      rnrb *= 2;
